79	func (s *statsCollector) recordRoundTrip(name string, requestBytes, responseBytes int64) {
80		if !s.enabled {
81			return
82		}
83		s.mu.Lock()
84		defer s.mu.Unlock()
85		item := s.ensure(name)
86		item.Requests++
87		item.RequestBytes += requestBytes
88		item.ResponseBytes += responseBytes
89	}
