92	// Counters are tracked unconditionally (independent of ShowStats) so the
93	// live progress ticker works without forcing --stats.
94	func (s *statsCollector) side(label string) *sideCounter {
95		s.sidesMu.RLock()
96		if sc, ok := s.sides[label]; ok {
97			s.sidesMu.RUnlock()
98			return sc
99		}
100		s.sidesMu.RUnlock()
101	
102		s.sidesMu.Lock()
103		defer s.sidesMu.Unlock()
104		if sc, ok := s.sides[label]; ok {
105			return sc
106		}
107		sc := &sideCounter{}
108		s.sides[label] = sc
109		return sc
110	}
