	ep, err := transport.ParseURL(raw.URL)
	if err != nil {
		return nil, fmt.Errorf("parse endpoint: %w", err)
	}
	authEp := auth.Endpoint{
		Username:      raw.Username,
		Token:         raw.Token,
		BearerToken:   raw.BearerToken,
		SkipTLSVerify: raw.SkipTLSVerify,
	}
