	}
	s := string(b)
	for s != "" {
		i := strings.IndexAny(s, "\r\n")
		if i < 0 {
			w.buf.WriteString(s)
			break
		}
		w.buf.WriteString(s[:i])
		line := w.buf.String()
		w.buf.Reset()
		// '\r' marks an in-place sideband update (git's
