// batch can still over-shoot if sent_bytes ≈ limit on every retry, so
// factor stays at 2 indefinitely). Always subdividing once guarantees
// the post-rejection retry makes progress instead of returning the
// caller into a hard failure.
func subdivideToFactor(
	chain []plumbing.Hash,
	current plumbing.Hash,
	remaining []plumbing.Hash,
	targetCount int,
) []plumbing.Hash {
	expanded := subdivideCheckpoints(chain, current, remaining)
	if len(expanded) <= len(remaining) {
