	for i := 0; i < sampleCapacity; i++ {
		r.push(sample{at: base.Add(time.Duration(i) * 200 * time.Millisecond), bytes: 1024})
	}
	if got := r.instantRate(); got != 0 {
		t.Errorf("flat byte count across ring should report 0, got %v", got)
